    return !!obj;
  }

  for (var i = 0; i < path.length; i++) {
    var j = getKey(path[i]);

    if((typeof j === 'number' && isArray(obj) && j < obj.length) ||
      (options.includeInheritedProps ? (j in Object(obj)) : hasOwnProperty(obj, j))) {
      obj = obj[j];
    } else {
      return false;
    }
  }

  return true;
};

